!function(){function esc(v){return v?String(v).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c])):""}function fmt(v){if(!v)return"";const d=new Date(v);if(isNaN(d.getTime()))return esc(v);const m=["Jan","Feb","Mar","Apr","Mei","Jun","Jul","Agu","Sep","Okt","Nov","Des"];return`${String(d.getDate()).padStart(2,"0")} ${m[d.getMonth()]} ${d.getFullYear()}, ${String(d.getHours()).padStart(2,"0")}:${String(d.getMinutes()).padStart(2,"0")}`}function statusOf(item){const now=Date.now(),user=State&&State.user&&State.user.id,submitted=user&&"1"===localStorage.getItem(`CBT_SUBMITTED_${item.id}_${State.user.id}`),finished=State&&State._schedulesForUserId===(State.user&&State.user.id)&&("SELESAI"===item.status||"SELESAI"===item._lastRenderedStatus);let rowClass="locked",badge="Login Dulu",detail="Belum Login",action="🔒 Login Dulu",disabled=!0,actionType="start",hasResult=!1;if(user){if(now<item.mulai){rowClass="waiting";badge="Belum Mulai";detail="Belum Waktunya";action="🔒 Login Dulu";disabled=!0}else if(submitted||finished){rowClass="done";badge="Sudah Dikerjakan";detail="Sudah Dikerjakan";action="Lihat Nilai";disabled=!0;hasResult=!0}else if(now>=item.selesai||"TUTUP"===item.status){rowClass="expired";badge="Ujian Sudah Selesai";detail="Ujian Sudah Selesai";action="Ujian Selesai";disabled=!0}else{const ver=window.getScheduleVersion?getScheduleVersion(item):String(item.versi_soal||0);if(null!==localStorage.getItem(`SOAL_${item.id}_v${ver}`)){const ts=localStorage.getItem(`SOAL_${item.id}_v${ver}_date`);rowClass="active";badge=ts&&Date.now()-parseInt(ts)>36e5?"Cache Ready":"Aktif";detail="Siap";action="▶ Mulai Ujian";disabled=!1;actionType="start"}else{rowClass="sync";badge="Belum Sinkron";detail="Unduh soal dulu";action="🔄 Sinkronisasi";disabled=!1;actionType="sync"}}}return{rowClass,badge,detail,action,disabled,actionType,hasResult}}function getSchedules(){let list=Array.isArray(State&&State.schedules)?State.schedules.filter(Boolean):[];if(!list.length)try{const raw=localStorage.getItem("CBT_CACHE_JADWAL");if(raw){const data=JSON.parse(raw)||{};list=Object.keys(data).map(id=>({id,...data[id]}))}}catch(e){}if(State&&State.user&&State.user.kelas){const kelas=String(State.user.kelas).toLowerCase();list=list.filter(item=>{const target=item.target_kelas||item.kelas_target||item.kelas||"";if(!target||"SEMUA"===String(target).toUpperCase()||"ALL"===String(target).toUpperCase())return true;return String(target).split(",").map(s=>s.trim().toLowerCase()).filter(Boolean).some(s=>kelas.includes(s)||s.includes(kelas))})}return list}function renderScheduleTable(){const listEl=document.getElementById("mobile-schedule-list"),countEl=document.getElementById("schedule-count");if(!listEl)return;const items=getSchedules();if(countEl)countEl.textContent=String(items.length);if(!items.length){listEl.innerHTML='<div class="mobile-empty schedule-empty"><div class="mobile-empty-illustration schedule-empty-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M7 3.75v3M17 3.75v3M4.75 8.5h14.5M6.5 5.75h11A2.5 2.5 0 0 1 20 8.25v9A2.75 2.75 0 0 1 17.25 20H6.75A2.75 2.75 0 0 1 4 17.25v-9a2.5 2.5 0 0 1 2.5-2.5Z"></path><path d="M9 13h6M9 16h3"></path></svg></div><h4>Belum bisa sinkron</h4><p>Data jadwal ujian masih kosong atau belum aktif.</p></div>';return}let html='<div class="schedule-table-wrap"><table class="schedule-table"><thead><tr><th>Mapel</th><th>Tgl / Jam</th><th>Kondisi</th></tr></thead><tbody>';for(const item of items){const st=statusOf(item);const action=st.hasResult?"view-result":st.actionType||"start";html+=`\n<tr class="schedule-row ${st.rowClass}">\n  <td class="schedule-subject"><div class="schedule-subject-name">${esc(item.nama||"Ujian")}</div><div class="schedule-subject-meta">${esc(st.detail)}</div></td>\n  <td class="schedule-datetime">${esc(fmt(item.mulai))} - ${esc(fmt(item.selesai))}</td>\n  <td class="schedule-condition"><span class="schedule-status-pill">${esc(st.badge)}</span><button class="schedule-action-btn" data-exam-id="${esc(item.id)}" data-action="${esc(action)}" ${st.disabled?"disabled":""}>${esc(st.action)}</button></td>\n</tr>`}html+='</tbody></table></div>';listEl.innerHTML=html;listEl.querySelectorAll(".schedule-action-btn:not([disabled])").forEach(btn=>btn.addEventListener("click",async()=>{const action=btn.dataset.action,id=btn.dataset.examId;if("view-result"===action){if(!State.user)return;window.showLoading("Mengambil nilai...");try{const res=await window.gasRun("getStudentResult",id,State.user.id);res.success?(localStorage.setItem("CBT_LAST_RESULT",JSON.stringify(res.result)),window.location.href="result.html"):window.showCustomAlert("Info",res.message||"Gagal mengambil nilai.","ℹ️")}catch(err){window.showCustomAlert("Error","Gagal memuat nilai: "+err.message,"❌")}finally{window.hideLoading()}return}const item=(State.schedules||[]).find(x=>x.id===id);item&&("sync"===action?syncSingleExam(item):"start"===action&&handleMobileScheduleTap(item))}))}function patch(){const base=window.renderMobileSchedule;if("function"!==typeof base||base._scheduleTablePatched)return;const wrapped=function(){return renderScheduleTable()};wrapped._scheduleTablePatched=!0;window.renderMobileSchedule=wrapped}function boot(){patch();renderScheduleTable()}document.addEventListener("DOMContentLoaded",()=>setTimeout(boot,0));window.addEventListener("load",()=>{boot();setTimeout(boot,300);setTimeout(boot,1200)});window.CBTScheduleTable={refresh:renderScheduleTable}}();
